import React, { useEffect, useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import jsPDF from "jspdf";
import html2canvas from "html2canvas";
import "../styles/Certificado.css";

const CertificadoBancario = () => {
  const navigate = useNavigate();

  const [usuario, setUsuario] = useState({
    nombre: "",
    documento: "",
    cuenta: "",
    tipoCuenta: "Ahorros Digital",
    estado: "Activa",
    saldo: "$0 COP",
  });

  // OBTENER DATOS REALES DESDE LA BASE DE DATOS
  useEffect(() => {
    const doc = localStorage.getItem("documento");

    if (!doc) {
      navigate("/login");
      return;
    }

    const obtenerUsuario = async () => {
      try {
        const response = await fetch(
          `http://127.0.0.1:8000/usuario-documento/${doc}`
        );

        if (!response.ok) {
          throw new Error("No se pudo obtener el usuario");
        }

        const data = await response.json();

        setUsuario({
          nombre: data.nombre || "Usuario no encontrado",
          documento: data.documento || doc,
          cuenta: data.numero_cuenta || "9800456721",
          tipoCuenta: data.tipo_cuenta || "Ahorros Digital",
          estado: data.estado || "Activa",
          saldo: data.saldo
            ? `$${Number(data.saldo).toLocaleString("es-CO")} COP`
            : "$0 COP",
        });
      } catch (error) {
        console.error("Error obteniendo usuario:", error);

        setUsuario({
          nombre: "Usuario",
          documento: doc,
          cuenta: "No disponible",
          tipoCuenta: "Ahorros Digital",
          estado: "Activa",
          saldo: "$0 COP",
        });
      }
    };

    obtenerUsuario();
  }, [navigate]);

  // BLOQUEAR BOTÓN ATRÁS
  useEffect(() => {
    window.history.pushState(null, "", window.location.href);

    const bloquear = () => {
      window.history.pushState(null, "", window.location.href);
    };

    window.addEventListener("popstate", bloquear);

    return () => {
      window.removeEventListener("popstate", bloquear);
    };
  }, []);

  // CERRAR SESIÓN
  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  // DESCARGAR PDF
  const descargarPDF = async () => {
    const elemento = document.getElementById("certificado-pdf");

    const canvas = await html2canvas(elemento, {
      scale: 2,
      useCORS: true,
    });

    const imgData = canvas.toDataURL("image/png");

    const pdf = new jsPDF("p", "mm", "a4");

    const imgWidth = 190;
    const imgHeight = (canvas.height * imgWidth) / canvas.width;

    pdf.addImage(imgData, "PNG", 10, 10, imgWidth, imgHeight);

    pdf.save(`Certificado_${usuario.documento}.pdf`);
  };

  const fechaActual = new Date().toLocaleDateString("es-CO", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });

  return (
    <div className="panel-financiero">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <ul>
          <li>
            <Link to="/cuenta">💷 Cuenta</Link>
          </li>

          <li>
            <Link to="#">📜 Historial Monetario</Link>
          </li>

          <li>
            <Link to="/transferencias">💳 Transferencias</Link>
          </li>

          <li>
            <Link to="/certificado" className="active">
              📄 Certificado Bancario
            </Link>
          </li>

          <li>
            <Link to="#">⚙️ Ajustes</Link>
          </li>
        </ul>

        <button className="logout" onClick={handleLogout}>
          🚪 Cerrar sesión
        </button>
      </aside>

      {/* CONTENIDO */}
      <main className="main">
        <header className="main-header">
          <h1>Certificado Bancario</h1>

          <div className="profile">
            <img
              src="https://i.pinimg.com/736x/e0/06/16/e00616c1e181f83b35b157f9281bd36e.jpg"
              alt="Usuario"
            />
          </div>
        </header>

        {/* CERTIFICADO */}
        <div className="certificado-container">
          <div className="certificado" id="certificado-pdf">
            <div className="header">
              <h1>BC Wallet</h1>
              <h2>Certificado Bancario</h2>
            </div>

            <div className="contenido">
              <p>La presente certifica que el(la) señor(a):</p>

              <h3 className="nombre">{usuario.nombre}</h3>

              <p>Identificado(a) con Cédula de Ciudadanía No:</p>

              <h4 className="documento">{usuario.documento}</h4>

              <p>
                Es titular de una cuenta en nuestra billetera digital con los
                siguientes datos:
              </p>

              <ul>
                <li>
                  <strong>Número de cuenta:</strong> {usuario.cuenta}
                </li>
                <li>
                  <strong>Tipo de cuenta:</strong> {usuario.tipoCuenta}
                </li>
                <li>
                  <strong>Estado:</strong> {usuario.estado}
                </li>
                <li>
                  <strong>Saldo actual:</strong> {usuario.saldo}
                </li>
              </ul>

              <p>
                Este certificado se expide en la ciudad de Bogotá D.C. el día:
              </p>

              <h4 className="fecha">{fechaActual}</h4>
            </div>

            <div className="footer">
              <p>Firma autorizada</p>
              <div className="firma"></div>
              <p>BC Wallet S.A.S</p>
            </div>
          </div>
        </div>

        {/* BOTÓN PDF */}
        <div className="descargar-container">
          <button className="btn-descargar" onClick={descargarPDF}>
            📥 Descargar Certificado en PDF
          </button>
        </div>
      </main>
    </div>
  );
};

export default CertificadoBancario;
